   268‚Üí      : buf.text;
   269‚Üí
   270‚Üí    const embed = {
   271‚Üí      author: { name: `${brand.label}`, ...(brand.iconUrl ? { icon_url: brand.iconUrl } : {}) },
   272‚Üí      description: truncated,
   273‚Üí      color: brand.color,
   274‚Üí    };
