   281‚Üí        const newId = await this.discord.sendToThread(session.threadId, { embed });
   282‚Üí        if (newId) buf.messageId = newId;
   283‚Üí      }
   284‚Üí    } else {
   285‚Üí      // First chunk ‚Äî send new message, remember ID for edits
   286‚Üí      const msgId = await this.discord.sendToThread(session.threadId, { embed });
   287‚Üí      if (msgId) buf.messageId = msgId;
   288‚Üí    }
