   379‚Üí  /**
   380‚Üí   * Track file paths from SDK tool calls.
   381‚Üí   * After 3+ paths sharing a common project root, auto-update session cwd.
   382‚Üí   */
   383‚Üí  private trackSdkPath(sessionId: string, filePath: string): void {
   384‚Üí    if (!this.sdkFilePaths.has(sessionId)) {
   385‚Üí      this.sdkFilePaths.set(sessionId, []);
   386‚Üí    }
   387‚Üí    const paths = this.sdkFilePaths.get(sessionId)!;
   388‚Üí    paths.push(filePath);
   389‚Üí    if (paths.length < 3) return;
   390‚Üí
   391‚Üí    // Find common root (deepest shared directory)
   392‚Üí    const segments = paths.map(p => p.split('/'));
   393‚Üí    const common: string[] = [];
   394‚Üí    for (let i = 0; i < segments[0].length; i++) {
   395‚Üí      const seg = segments[0][i];
   396‚Üí      if (segments.every(s => s[i] === seg)) {
   397‚Üí        common.push(seg);
   398‚Üí      } else {
   399‚Üí        break;
   400‚Üí      }
   401‚Üí    }
   402‚Üí    const commonRoot = common.join('/');
   403‚Üí
   404‚Üí    // Skip if root is too shallow ($HOME or above)
   405‚Üí    const home = getUserHome();
   406‚Üí    if (!commonRoot || commonRoot === home || commonRoot.split('/').length <= home.split('/').length) {
   407‚Üí      return;
   408‚Üí    }
   409‚Üí
   410‚Üí    // Find the likely project root (directory containing .git, package.json, etc.)
   411‚Üí    const projectRoot = this.findProjectRoot(commonRoot);
   412‚Üí    const session = this.registry.getSession(sessionId);
   413‚Üí    if (!session) return;
   414‚Üí
   415‚Üí    // Only update if different from current cwd and not already a project dir
   416‚Üí    if (session.cwd === projectRoot) return;
   417‚Üí
   418‚Üí    const oldProject = session.project;
   419‚Üí    session.cwd = projectRoot;
   420‚Üí    session.project = projectRoot.split('/').pop() || session.project;
   421‚Üí    this.store.setSession(session);
   422‚Üí    this.sdkCwdLocked.add(sessionId); // Don't re-detect after auto-update
   423‚Üí
   424‚Üí    // Notify in thread
   425‚Üí    if (session.threadId) {
   426‚Üí      this.discord.sendToThread(session.threadId, {
   427‚Üí        embed: {
   428‚Üí          title: `üìÇ Auto-detected: ${oldProject} ‚Üí ${session.project}`,
   429‚Üí          description: `\`${collapseHome(projectRoot)}\``,
   430‚Üí          color: 0x5865F2,
   431‚Üí        },
   432‚Üí      }).catch(() => {});
   433‚Üí    }
   434‚Üí
   435‚Üí    // Refresh hub card
   436‚Üí    this.registry.emit('session:active', session);
   437‚Üí    console.log(`[router] Auto-cwd: ${sessionId.slice(0, 8)} ‚Üí ${projectRoot}`);
   438‚Üí  }
