   440‚Üí  /** Walk up from a path to find the nearest project root */
   441‚Üí  private findProjectRoot(dir: string): string {
   442‚Üí    const markers = ['.git', 'package.json', 'Cargo.toml', 'go.mod', 'pyproject.toml', 'pom.xml'];
   443‚Üí    let current = dir;
   444‚Üí    const home = getUserHome();
   445‚Üí    while (current.length > home.length) {
   446‚Üí      for (const marker of markers) {
   447‚Üí        try {
   448‚Üí          fs.statSync(`${current}/${marker}`);
   449‚Üí          return current;
   450‚Üí        } catch { /* continue */ }
   451‚Üí      }
   452‚Üí      const parent = current.slice(0, current.lastIndexOf('/'));
   453‚Üí      if (parent === current) break;
   454‚Üí      current = parent;
   455‚Üí    }
   456‚Üí    return dir; // fallback to the common root itself
   457‚Üí  }
