   459‚Üí  start(): void {
   460‚Üí    // CLI ‚Üí IM: route events from IPC to Discord threads
   461‚Üí    this.registry.on('session:event', (session, msg) => {
   462‚Üí      this.routeToIM(session, msg).catch(err => {
   463‚Üí        console.error(`[router] Error routing to IM:`, err);
   464‚Üí      });
   465‚Üí    });
   466‚Üí
   467‚Üí    // CLI ‚Üí IM: permission requests
   468‚Üí    this.ipc.on('permission_request', (msg) => {
   469‚Üí      this.handlePermissionRequest(msg).catch(err => {
   470‚Üí        console.error(`[router] Error handling permission request:`, err);
   471‚Üí      });
   472‚Üí    });
   473‚Üí
   474‚Üí    // IM ‚Üí CLI: messages from Discord threads
   475‚Üí    this.discord.onInboundMessage = (session, text, userId) => {
   476‚Üí      this.routeFromIM(session, text, userId).catch(err => {
   477‚Üí        console.error(`[router] Error routing from IM:`, err);
   478‚Üí      });
   479‚Üí    };
   480‚Üí
   481‚Üí    // IM ‚Üí CLI: permission decisions from Discord buttons
   482‚Üí    this.discord.onPermissionDecision = (permissionId, decision) => {
   483‚Üí      this.handlePermissionDecision(permissionId, decision);
   484‚Üí    };
   485‚Üí
   486‚Üí    // Hub channel commands (delegated from Discord adapter)
   487‚Üí    this.discord.onHubCommand = (command, args, ctx) => {
   488‚Üí      this.handleHubCommand(command, args, ctx).catch(err => {
   489‚Üí        console.error('[router] Error handling hub command:', err);
   490‚Üí      });
   491‚Üí    };
   492‚Üí
   493‚Üí    // Claude transcript watcher: forward assistant text on session register
   494‚Üí    // Skip SDK sessions ‚Äî their output is already routed via stream events
   495‚Üí    this.registry.on('session:registered', (session) => {
   496‚Üí      if (session.agent !== 'codex' && session.source !== 'sdk') {
   497‚Üí        this.transcriptWatcher.startWatching(session.sessionId, session.cwd);
