   499‚Üí    });
   500‚Üí    this.registry.on('session:ended', (session) => {
   501‚Üí      this.transcriptWatcher.stopWatching(session.sessionId);
   502‚Üí    });
   503‚Üí    this.transcriptWatcher.on('assistant:text', (sessionId, text) => {
   504‚Üí      this.handleAssistantText(sessionId, text).catch(err => {
   505‚Üí        console.error('[router] Error sending assistant text:', err);
   506‚Üí      });
   507‚Üí    });
   508‚Üí
   509‚Üí    // Codex auto-detection: discovers sessions from SQLite, no wrapper needed
   510‚Üí    if (this.codexWatcherEnabled) {
   511‚Üí      this.codexWatcher.start();
   512‚Üí      this.codexWatcher.on('session:new', (thread) => {
   513‚Üí        this.handleCodexSessionNew(thread).catch(err => {
   514‚Üí          console.error('[router] Error registering codex session:', err);
   515‚Üí        });
   516‚Üí      });
   517‚Üí      this.codexWatcher.on('session:ended', (threadId) => {
   518‚Üí        const sid = `codex-${threadId}`;
   519‚Üí        this.registry.handleUnregister({ type: 'unregister', sessionId: sid });
   520‚Üí      });
   521‚Üí      this.codexWatcher.on('assistant:text', (threadId, text) => {
   522‚Üí        this.handleAssistantText(`codex-${threadId}`, text).catch(err => {
   523‚Üí          console.error('[router] Error sending codex text:', err);
