   550‚Üí  private async handleHubCommand(command: string, args: string, ctx: HubReplyContext): Promise<void> {
   551‚Üí    const normalized = this.normalizeCommand(command);
   552‚Üí    switch (normalized) {
   553‚Üí      case '!new': {
   554‚Üí        if (!this.sdkManager || !this.mmsEnv) {
   555‚Üí          await ctx.reply('ÂΩìÂâçÊú™ÈÖçÁΩÆ SDK„ÄÇ');
   556‚Üí          return;
   557‚Üí        }
   558‚Üí        // /new [model] [cwd] prompt...
   559‚Üí        // model: exact name or prefix (e.g. "kimi" ‚Üí "kimi-for-coding")
   560‚Üí        // cwd: full path, ~, or project name shortcut (matches recent session projects)
   561‚Üí        const parts = args.split(/\s+/);
   562‚Üí        let model = this.mmsEnv.getDefaultModel();
   563‚Üí        let cwd = getUserHome();
   564‚Üí        let promptParts = [...parts];
   565‚Üí
   566‚Üí        // Check if first arg matches a model (fuzzy)
   567‚Üí        if (parts[0] && this.mmsEnv.resolveModel(parts[0])) {
   568‚Üí          model = this.mmsEnv.resolveModel(parts[0])!.resolvedId;
   569‚Üí          promptParts = parts.slice(1);
   570‚Üí        }
   571‚Üí
   572‚Üí        // Check if next arg is a cwd specifier
   573‚Üí        if (promptParts[0]) {
   574‚Üí          const cwdArg = promptParts[0];
   575‚Üí          if (cwdArg.startsWith('/')) {
   576‚Üí            cwd = cwdArg;
   577‚Üí            promptParts = promptParts.slice(1);
   578‚Üí          } else if (cwdArg.startsWith('~')) {
   579‚Üí            cwd = expandHome(cwdArg);
   580‚Üí            promptParts = promptParts.slice(1);
   581‚Üí          } else if (promptParts.length >= 2) {
   582‚Üí            // Only try project shortcut if there's still a prompt after it
   583‚Üí            const matched = this.resolveCwdShortcut(cwdArg);
   584‚Üí            if (matched) {
   585‚Üí              cwd = matched;
   586‚Üí              promptParts = promptParts.slice(1);
   587‚Üí            }
   588‚Üí          }
   589‚Üí        }
   590‚Üí
   591‚Üí        const prompt = promptParts.join(' ');
   592‚Üí        if (!prompt) {
   593‚Üí          await ctx.reply('Áî®Ê≥ï: `!new [model] [cwd] <prompt>`\nmodel / cwd ÈÉΩÊîØÊåÅÊ®°Á≥äÂåπÈÖç„ÄÇ');
   594‚Üí          return;
   595‚Üí        }
   596‚Üí
   597‚Üí        const provider = this.mmsEnv.resolveProvider(model);
   598‚Üí        await ctx.reply(`Ê≠£Âú®ÂêØÂä®: **${model}** in \`${collapseHome(cwd)}\`...`);
   599‚Üí
   600‚Üí        try {
   601‚Üí          const sessionId = await this.sdkManager.startSession(prompt, {
   602‚Üí            cwd,
   603‚Üí            model,
   604‚Üí            provider,
   605‚Üí          });
   606‚Üí          console.log(`[router] /new ‚Üí SDK session started: ${sessionId.slice(0, 12)}`);
   607‚Üí
   608‚Üí          // Wait for thread creation
   609‚Üí          await new Promise(r => setTimeout(r, 2000));
   610‚Üí          const session = this.registry.getSession(sessionId);
   611‚Üí          if (session) {
   612‚Üí            // Set title from prompt for hub card
   613‚Üí            const shortPrompt = prompt.length > 60 ? prompt.slice(0, 57) + '...' : prompt;
   614‚Üí            session.title = shortPrompt;
   615‚Üí            session.model = model;
   616‚Üí            this.store.setSession(session);
   617‚Üí            this.registry.emit('session:active', session);
   618‚Üí            if (session.threadId) {
   619‚Üí              await ctx.reply(`Thread created: ${session.threadId}`);
   620‚Üí            }
   621‚Üí          }
   622‚Üí        } catch (err) {
   623‚Üí          const errMsg = err instanceof Error ? err.message : String(err);
   624‚Üí          await ctx.reply(`ÂêØÂä®Â§±Ë¥•: ${errMsg}`);
   625‚Üí        }
   626‚Üí        break;
   627‚Üí      }
   628‚Üí
   629‚Üí      case '!clean': {
   630‚Üí        // Finalize all non-dead sessions and clean up hub cards
   631‚Üí        let cleaned = 0;
   632‚Üí        for (const session of this.registry.listAll()) {
   633‚Üí          if (session.status === 'dead') continue;
   634‚Üí          this.registry.finalizeEnded(session.sessionId);
   635‚Üí          cleaned++;
   636‚Üí        }
   637‚Üí        await ctx.reply(cleaned > 0 ? `Â∑≤Ê∏ÖÁêÜ ${cleaned} ‰∏™ session„ÄÇ` : 'ÂΩìÂâçÊ≤°ÊúâÂèØÊ∏ÖÁêÜÁöÑ session„ÄÇ');
   638‚Üí        break;
   639‚Üí      }
   640‚Üí
   641‚Üí      case '!help': {
   642‚Üí        await ctx.reply([
   643‚Üí          '**Hub ÂëΩ‰ª§:**',
   644‚Üí          '`!new [model] [cwd] <prompt>` ‚Äî ÂêØÂä®‰∏Ä‰∏™Êñ∞ÁöÑ SDK session',
   645‚Üí          '`!help` ‚Äî ÊòæÁ§∫Â∏ÆÂä©',
   646‚Üí          '`!status` ‚Äî ÂàóÂá∫ÂΩìÂâçÂèØËßÅ session',
   647‚Üí          '`!clean` ‚Äî Ê∏ÖÁêÜÊâÄÊúâ session Âç°Áâá',
   648‚Üí          '',
   649‚Üí          '**Thread ÂëΩ‰ª§:**',
   650‚Üí          '`!help` ‚Äî ÊòæÁ§∫ thread Â∏ÆÂä©',
   651‚Üí          '`!filter full|summary|compact|silent` ‚Äî ÂàáÊç¢ËøáÊª§Á∫ßÂà´',
   652‚Üí          '`!model <name>` ‚Äî ÂàáÊç¢ modelÔºàÊîØÊåÅÊ®°Á≥äÂåπÈÖçÔºâ',
   653‚Üí          '`!models` ‚Äî Êü•ÁúãÂèØÁî® model',
   654‚Üí          '`!cd <name>` ‚Äî ÂàáÊç¢ cwdÔºàzoxide / ÊúÄËøë sessionÔºâ',
   655‚Üí          '`!info` ‚Äî Êü•Áúã session ‰ø°ÊÅØ',
   656‚Üí          '`!abort` ‚Äî ‰∏≠Ê≠¢ÂΩìÂâç SDK turn',
   657‚Üí          '`!done` ‚Äî ÂÖ≥Èó≠ÂΩìÂâç session Âπ∂ÂΩíÊ°£ thread',
   658‚Üí          '',
   659‚Üí          'ÊñáÊú¨ÂëΩ‰ª§ÊîØÊåÅ `!` / `/` / ÂÖ®Ëßí `ÔºÅ` / `Ôºè` ÂâçÁºÄ„ÄÇ',
   660‚Üí        ].join('\n'));
   661‚Üí        break;
   662‚Üí      }
   663‚Üí
   664‚Üí      default:
   665‚Üí        await ctx.reply('Êú™Áü•ÂëΩ‰ª§ÔºåËØïËØï `!help`');
   666‚Üí    }
   667‚Üí  }
