   690‚Üí  // ‚îÄ‚îÄ Transcript ‚Üí IM (assistant text output) ‚îÄ‚îÄ
   691‚Üí
   692‚Üí  private async handleAssistantText(sessionId: string, text: string): Promise<void> {
   693‚Üí    const session = this.registry.getSession(sessionId);
   694‚Üí    if (!session?.threadId) return;
   695‚Üí    if (session.filterLevel === 'silent') return;
   696‚Üí    // Skip SDK sessions ‚Äî their output is routed via stream events, not transcript
   697‚Üí    if (session.source === 'sdk') return;
   698‚Üí
   699‚Üí    const previous = this.lastAssistantText.get(sessionId);
   700‚Üí    if (previous && previous.text === text && Date.now() - previous.at < 15_000) {
   701‚Üí      console.log(`[router] Skip duplicate assistant text for ${sessionId.slice(0, 8)}`);
   702‚Üí      return;
   703‚Üí    }
   704‚Üí    this.lastAssistantText.set(sessionId, { text, at: Date.now() });
   705‚Üí
   706‚Üí    const brand = getAgentBrand(session.agent);
   707‚Üí    const author = { name: brand.label, ...(brand.iconUrl ? { icon_url: brand.iconUrl } : {}) };
   708‚Üí
   709‚Üí    // Discord embed description limit is 4096 chars
   710‚Üí    const truncated = text.length > 3800
   711‚Üí      ? text.slice(0, 3800) + `\n*[${text.length} chars total]*`
   712‚Üí      : text;
   713‚Üí
   714‚Üí    await this.discord.sendToThread(session.threadId, {
   715‚Üí      embed: {
   716‚Üí        author,
   717‚Üí        description: truncated,
   718‚Üí        color: brand.color,
   719‚Üí      },
   720‚Üí    });
   721‚Üí  }
