   762‚Üí  // ‚îÄ‚îÄ CLI ‚Üí IM ‚îÄ‚îÄ
   763‚Üí
   764‚Üí  private async routeToIM(session: CLISession, msg: EventMsg): Promise<void> {
   765‚Üí    if (!session.threadId) return;
   766‚Üí
   767‚Üí    // Track context for title updates (before filter ‚Äî track all events)
   768‚Üí    this.extractContext(session, msg);
   769‚Üí    await this.maybeUpdateTitle(session);
   770‚Üí
   771‚Üí    const event = msg.event;
   772‚Üí    const level = session.filterLevel;
   773‚Üí
   774‚Üí    // Extract tool name for filter decision
   775‚Üí    const toolName = (event === 'tool_use' || event === 'tool_result')
   776‚Üí      ? ((msg.data as { tool?: string; name?: string }).tool || (msg.data as { name?: string }).name)
   777‚Üí      : undefined;
   778‚Üí
   779‚Üí    // Filter check
   780‚Üí    if (!this.shouldForward(event, level, toolName)) return;
   781‚Üí
   782‚Üí    // In summary mode, tool_result gets a compact one-line rendering
   783‚Üí    if (level === 'summary' && event === 'tool_result') {
   784‚Üí      const d = msg.data as { tool?: string; input?: unknown; is_error?: boolean };
   785‚Üí      const inp = this.parseInput(d.input);
   786‚Üí      let summary = '';
   787‚Üí      if (inp.command) summary = String(inp.command).slice(0, 80);
   788‚Üí      else if (inp.file_path) summary = String(inp.file_path);
   789‚Üí      else if (inp.pattern) summary = String(inp.pattern);
   790‚Üí      const icon = d.is_error ? '\u274c' : '\u2705';
   791‚Üí      await this.discord.sendToThread(session.threadId, `${icon} **${d.tool || 'tool'}** ${summary}`);
   792‚Üí      return;
   793‚Üí    }
   794‚Üí
   795‚Üí    const rendered = this.renderEvent(event, msg.data, session.agent);
   796‚Üí    await this.discord.sendToThread(session.threadId, rendered);
   797‚Üí  }
