   799‚Üí  private async handlePermissionRequest(msg: PermissionRequestMsg): Promise<void> {
   800‚Üí    const session = this.registry.getSession(msg.sessionId);
   801‚Üí    if (!session?.threadId) {
   802‚Üí      console.warn(`[router] Permission ${msg.permissionId.slice(0, 8)} allowed locally: no IM thread bound for ${msg.sessionId.slice(0, 8)}`);
   803‚Üí      this.ipc.resolvePermission(msg.permissionId, 'allow', 'No IM thread bound; falling back to local approval');
   804‚Üí      return;
   805‚Üí    }
   806‚Üí
   807‚Üí    // Store pending permission
   808‚Üí    this.store.setPendingPermission({
   809‚Üí      permissionId: msg.permissionId,
   810‚Üí      sessionId: msg.sessionId,
   811‚Üí      toolName: msg.toolName,
   812‚Üí      toolInput: msg.toolInput,
   813‚Üí      createdAt: new Date().toISOString(),
   814‚Üí    });
   815‚Üí
   816‚Üí    // Send buttons to Discord thread
   817‚Üí    const discordMsgId = await this.discord.sendPermissionButtons(
   818‚Üí      session.threadId,
   819‚Üí      msg.permissionId,
   820‚Üí      msg.toolName,
   821‚Üí      msg.toolInput,
   822‚Üí    );
   823‚Üí
   824‚Üí    if (!discordMsgId) {
   825‚Üí      this.store.deletePendingPermission(msg.permissionId);
   826‚Üí      console.warn(`[router] Permission ${msg.permissionId.slice(0, 8)} allowed locally: failed to deliver IM approval request`);
   827‚Üí      this.ipc.resolvePermission(msg.permissionId, 'allow', 'IM approval delivery failed; falling back to local approval');
   828‚Üí      return;
   829‚Üí    }
   830‚Üí
   831‚Üí    const perm = this.store.getPendingPermission(msg.permissionId);
