   838‚Üí  private handlePermissionDecision(permissionId: string, decision: 'allow' | 'deny' | 'allow_all'): void {
   839‚Üí    // Try SDK interaction first (for SDK-based sessions)
   840‚Üí    if (this.sdkManager && this.sdkManager.resolveInteraction(permissionId, decision)) {
   841‚Üí      console.log(`[router] SDK permission ${permissionId.slice(0, 12)} ${decision}`);
   842‚Üí      return;
   843‚Üí    }
   844‚Üí
   845‚Üí    // Fall back to IPC socket (for hook-based sessions) ‚Äî IPC only knows allow/deny
   846‚Üí    const ipcDecision = decision === 'deny' ? 'deny' : 'allow';
   847‚Üí    const resolved = this.ipc.resolvePermission(permissionId, ipcDecision);
   848‚Üí    if (resolved) {
   849‚Üí      this.store.deletePendingPermission(permissionId);
   850‚Üí      console.log(`[router] Permission ${permissionId.slice(0, 8)} ${decision}`);
   851‚Üí    } else {
   852‚Üí      console.warn(`[router] No waiting socket for permission ${permissionId.slice(0, 8)}`);
   853‚Üí    }
   854‚Üí  }
