   858‚Üí  private async routeFromIM(session: CLISession, text: string, _userId: string): Promise<void> {
   859‚Üí    const trimmed = this.normalizeInboundText(text);
   860‚Üí
   861‚Üí    // Thread-level commands
   862‚Üí    if (trimmed.startsWith('!') || trimmed.startsWith('/')) {
   863‚Üí      await this.handleThreadCommand(session, trimmed);
   864‚Üí      return;
   865‚Üí    }
   866‚Üí
   867‚Üí    const recoveryToken = this.extractRecoveryToken(trimmed);
   868‚Üí    if (recoveryToken) {
   869‚Üí      await this.handleRecoveryToken(session, recoveryToken);
   870‚Üí      return;
   871‚Üí    }
   872‚Üí
   873‚Üí    // Numeric permission shortcut
   874‚Üí    if (/^[123]$/.test(trimmed)) {
   875‚Üí      const pending = this.store.getPendingBySession(session.sessionId);
   876‚Üí      if (pending.length > 0) {
   877‚Üí        const latest = pending[pending.length - 1];
   878‚Üí        const decision = trimmed === '3' ? 'deny' : 'allow';
   879‚Üí        this.handlePermissionDecision(latest.permissionId, decision);
   880‚Üí        return;
   881‚Üí      }
   882‚Üí    }
   883‚Üí
   884‚Üí    // Codex auto-detected sessions are observe-only for now.
   885‚Üí    // Never try to resume them via Claude SDK ‚Äî their session IDs are not Claude UUIDs.
   886‚Üí    if (session.agent === 'codex') {
   887‚Üí      if (session.threadId) {
   888‚Üí        await this.discord.sendToThread(
   889‚Üí          session.threadId,
   890‚Üí          '‚öÝÔ∏è ËøôÊòØ `observe-only` ÁöÑ Codex sessionÔºåÁ∫øÁ®ãÂÜÖÂõûÂ§çÊöÇÊó∂‰∏ç‰ºöÊ≥®ÂõûÊú¨Âú∞ÁªàÁ´Ø„ÄÇÂèØÁî® `!help` / `!info` / `!filter`ÔºåÊàñÁõ¥Êé•ÂõûÂà∞Êú¨Âú∞ Codex ÁªßÁª≠„ÄÇ',
   891‚Üí        );
   892‚Üí      }
   893‚Üí      return;
   894‚Üí    }
   895‚Üí
   896‚Üí    // Phase 2: Route message via Agent SDK
   897‚Üí    if (!this.sdkManager) {
   898‚Üí      console.log(`[router] IM ‚Üí CLI [${session.sessionId.slice(0, 8)}]: ${trimmed} (SDK not configured)`);
   899‚Üí      if (session.threadId) {
   900‚Üí        await this.discord.sendToThread(session.threadId, '‚öÝÔ∏è ÂΩìÂâçÊú™ÈÖçÁΩÆ SDK session manager„ÄÇ');
   901‚Üí      }
   902‚Üí      return;
   903‚Üí    }
   904‚Üí
   905‚Üí    // Check if SDK is running for this session
   906‚Üí    if (this.sdkManager.isRunning(session.sessionId)) {
   907‚Üí      if (session.threadId) {
   908‚Üí        await this.discord.sendToThread(session.threadId, '‚è≥ ÂΩìÂâç SDK turn ‰ªçÂú®ÊâßË°åÔºåÂÖàÁ≠âÂÆÉÁªìÊùü„ÄÇ');
   909‚Üí      }
   910‚Üí      return;
   911‚Üí    }
   912‚Üí
   913‚Üí    // CC is actively running locally ‚Äî can't resume (would conflict)
   914‚Üí    if (session.source === 'hook' && session.status === 'active') {
   915‚Üí      if (session.threadId) {
   916‚Üí        await this.discord.sendToThread(session.threadId, '‚è≥ Êú¨Âú∞ Claude Code ËøòÂú® active„ÄÇÁ≠âÂÆÉËøõÂÖ• idle ÂêéÂÜçËØï„ÄÇ');
   917‚Üí      }
   918‚Üí      return;
   919‚Üí    }
   920‚Üí
   921‚Üí    // Show typing indicator while LLM is working
   922‚Üí    if (session.threadId) {
   923‚Üí      this.discord.sendTyping(session.threadId).catch(() => {});
   924‚Üí    }
   925‚Üí
   926‚Üí    // Always try to resume first ‚Äî shared conversation history with CC
   927‚Üí    // Save prompt for retry if resume fails (signature error detected in stream)
   928‚Üí    this.sdkLastPrompt.set(session.sessionId, trimmed);
   929‚Üí    try {
   930‚Üí      const sid = await this.sdkManager.startSession(trimmed, {
   931‚Üí        resume: session.sessionId,
   932‚Üí        cwd: session.cwd,
   933‚Üí        model: session.model,
   934‚Üí        provider: session.provider,
   935‚Üí        ccBaseUrl: session.baseUrl,
   936‚Üí        ccAuthToken: session.authToken,
   937‚Üí      });
   938‚Üí      session.source = 'sdk';
   939‚Üí      session.status = 'active';
   940‚Üí      session.lastActivityAt = new Date().toISOString();
   941‚Üí      this.store.setSession(session);
   942‚Üí      this.transcriptWatcher.stopWatching(session.sessionId);
   943‚Üí      console.log(`[router] IM ‚Üí SDK resume [${sid.slice(0, 8)}]: ${trimmed.slice(0, 80)}`);
   944‚Üí      return;
   945‚Üí    } catch (err) {
   946‚Üí      const errMsg = err instanceof Error ? err.message : String(err);
   947‚Üí      console.warn(`[router] Resume failed: ${errMsg}`);
   948‚Üí
   949‚Üí      // Signature/thinking block error ‚Üí fallback to fresh, warn user
   950‚Üí      if (errMsg.includes('signature') || errMsg.includes('thinking') || errMsg.includes('400')) {
   951‚Üí        try {
   952‚Üí          if (session.threadId) {
   953‚Üí            await this.discord.sendToThread(session.threadId, `‚öÝÔ∏è ÊóÝÊ≥ïÊé•ÂÖ•Âéü sessionÔºàAPI key ‰∏çÂêåÔºâ„ÄÇÊú¨Ê¨°ÂõûÂ§ç‰∏ç‰ºöÂá∫Áé∞Âú® CC ‰∏≠„ÄÇ`);
   954‚Üí          }
   955‚Üí          const sid = await this.sdkManager.startSession(trimmed, {
   956‚Üí            cwd: session.cwd,
   957‚Üí            model: session.model,
   958‚Üí            provider: session.provider,
   959‚Üí          });
   960‚Üí          session.status = 'active';
   961‚Üí          session.lastActivityAt = new Date().toISOString();
   962‚Üí          this.store.setSession(session);
   963‚Üí          this.transcriptWatcher.stopWatching(session.sessionId);
   964‚Üí          console.log(`[router] IM ‚Üí SDK fresh (fallback) [${sid.slice(0, 8)}]: ${trimmed.slice(0, 80)}`);
   965‚Üí          return;
   966‚Üí        } catch (fbErr) {
   967‚Üí          const fbMsg = fbErr instanceof Error ? fbErr.message : String(fbErr);
   968‚Üí          if (session.threadId) {
   969‚Üí            await this.discord.sendToThread(session.threadId, `‚ùå ${fbMsg}`);
   970‚Üí          }
   971‚Üí          return;
   972‚Üí        }
   973‚Üí      }
   974‚Üí
   975‚Üí      if (session.threadId) {
   976‚Üí        await this.discord.sendToThread(session.threadId, `‚ùå ${errMsg}`);
   977‚Üí      }
   978‚Üí    }
   979‚Üí  }
