  1467‚Üí  private shouldForward(eventType: string, level: FilterLevel, toolName?: string): boolean {
  1468‚Üí    if (ALWAYS_FORWARD.has(eventType)) return true;
  1469‚Üí    if (level === 'full') return true;
  1470‚Üí    if (level === 'summary') {
  1471‚Üí      if (SUMMARY_EVENTS.has(eventType)) return true;
  1472‚Üí      // For tool events, only show tools that make changes
  1473‚Üí      if ((eventType === 'tool_use' || eventType === 'tool_result') && toolName) {
  1474‚Üí        return SUMMARY_TOOLS.has(toolName);
  1475‚Üí      }
  1476‚Üí      return false;
  1477‚Üí    }
  1478‚Üí    if (level === 'compact') return COMPACT_EVENTS.has(eventType);
  1479‚Üí    return false; // silent
  1480‚Üí  }
