  1493‚Üí  private extractContext(session: CLISession, msg: EventMsg): void {
  1494‚Üí    const ctx = this.getOrCreateContext(session.sessionId);
  1495‚Üí
  1496‚Üí    if (msg.event === 'user_prompt') {
  1497‚Üí      const d = msg.data as { prompt?: string };
  1498‚Üí      if (d.prompt) ctx.latestPrompt = d.prompt;
  1499‚Üí    }
  1500‚Üí
  1501‚Üí    if (msg.event === 'tool_result' || msg.event === 'tool_use') {
  1502‚Üí      const d = msg.data as { input?: unknown };
  1503‚Üí      const inp = this.parseInput(d.input);
  1504‚Üí      const filePath = inp.file_path as string | undefined;
  1505‚Üí      if (filePath && filePath.startsWith('/')) {
  1506‚Üí        ctx.recentPaths.push(filePath);
  1507‚Üí        if (ctx.recentPaths.length > 30) ctx.recentPaths = ctx.recentPaths.slice(-30);
  1508‚Üí      }
  1509‚Üí    }
  1510‚Üí  }
