  1512‚Üí  private async maybeUpdateTitle(session: CLISession): Promise<void> {
  1513‚Üí    if (!session.threadId) return;
  1514‚Üí    const ctx = this.getOrCreateContext(session.sessionId);
  1515‚Üí    const now = Date.now();
  1516‚Üí
  1517‚Üí    // Rate limit: 5 min cooldown
  1518‚Üí    if (now - ctx.lastTitleUpdate < ContentRouter.TITLE_COOLDOWN_MS) return;
  1519‚Üí    // Need a user prompt for meaningful title context (don't waste the first update on tool-only events)
  1520‚Üí    if (!ctx.latestPrompt) return;
  1521‚Üí
  1522‚Üí    const newTitle = this.generateTitle(session);
  1523‚Üí    if (newTitle === ctx.currentTitle) return;
  1524‚Üí    const updated = await this.discord.updateThreadTitle(session.threadId, newTitle);
  1525‚Üí    if (!updated) return;
  1526‚Üí
  1527‚Üí    ctx.currentTitle = newTitle;
  1528‚Üí    ctx.lastTitleUpdate = now;
  1529‚Üí
  1530‚Üí    // Extract short task summary for hub card
  1531‚Üí    const sctx = this.sessionContext.get(session.sessionId);
  1532‚Üí    if (sctx?.latestPrompt) {
  1533‚Üí      let summary = sctx.latestPrompt.split('\n')[0].trim();
