  1543‚Üí  /** Update SDK session title from prompt or response text */
  1544‚Üí  private async updateSdkTitle(sessionId: string, responseText: string): Promise<void> {
  1545‚Üí    const session = this.registry.getSession(sessionId);
  1546‚Üí    if (!session?.threadId) return;
  1547‚Üí
  1548‚Üí    // Use prompt as title (user's intent), fallback to response first line
  1549‚Üí    const prompt = this.sdkLastPrompt.get(sessionId) || '';
  1550‚Üí    let summary = prompt.split('\n')[0].trim();
  1551‚Üí    summary = summary.replace(/^(please|help me|can you|I want to|I need to|ËØ∑|Â∏ÆÊàë|Â∏ÆÂøô)\s*/i, '');
  1552‚Üí
  1553‚Üí    if (!summary) {
  1554‚Üí      const lines = responseText.split('\n').map(l => l.trim()).filter(Boolean);
  1555‚Üí      for (const line of lines) {
  1556‚Üí        const cleaned = line.replace(/^#{1,4}\s*/, '').replace(/\*{1,2}/g, '').trim();
  1557‚Üí        if (cleaned.length >= 3) { summary = cleaned; break; }
  1558‚Üí      }
  1559‚Üí    }
  1560‚Üí
  1561‚Üí    if (!summary) return;
  1562‚Üí    summary = summary.length > 50 ? summary.slice(0, 47) + '...' : summary;
  1563‚Üí
  1564‚Üí    const shortId = session.sessionId.slice(0, 6);
  1565‚Üí    const title = `${session.project} / ${session.branch} ‚Äî ${summary} [${shortId}]`;
  1566‚Üí    const truncated = title.length > 100 ? title.slice(0, 97) + '...' : title;
  1567‚Üí
  1568‚Üí    const updated = await this.discord.updateThreadTitle(session.threadId, truncated);
  1569‚Üí    if (!updated) return;
  1570‚Üí
  1571‚Üí    session.title = summary;
  1572‚Üí    this.store.setSession(session);
  1573‚Üí    this.registry.emit('session:active', session);
  1574‚Üí  }
