  1576‚Üí  private generateTitle(session: CLISession): string {
  1577‚Üí    const sctx = this.sessionContext.get(session.sessionId);
  1578‚Üí    const shortId = session.sessionId.slice(0, 6);
  1579‚Üí
  1580‚Üí    // Folder indicator ‚Äî detect cross-folder work
  1581‚Üí    let folderPart = session.project;
  1582‚Üí    if (sctx && sctx.recentPaths.length >= 3) {
  1583‚Üí      const effective = this.detectEffectiveProject(session.cwd, sctx.recentPaths);
  1584‚Üí      if (effective && effective !== session.project) {
  1585‚Üí        folderPart = `${session.project} \u2194 ${effective}`;
  1586‚Üí        sctx.crossFolderProject = effective;
  1587‚Üí      }
  1588‚Üí    }
  1589‚Üí
  1590‚Üí    // Base: "project ‚Üî target / branch"
  1591‚Üí    let title = `${folderPart} / ${session.branch}`;
  1592‚Üí
  1593‚Üí    // Context from latest prompt
  1594‚Üí    if (sctx?.latestPrompt) {
  1595‚Üí      let prompt = sctx.latestPrompt.split('\n')[0].trim();
  1596‚Üí      // Trim common prefixes
  1597‚Üí      prompt = prompt.replace(/^(please|help me|can you|I want to|I need to|ËØ∑|Â∏ÆÊàë|Â∏ÆÂøô)\s*/i, '');
  1598‚Üí      const maxLen = 100 - title.length - shortId.length - 7; // 7 = " ‚Äî " + " [" + "]"
  1599‚Üí      if (prompt && maxLen > 10) {
  1600‚Üí        const truncated = prompt.length > maxLen ? prompt.slice(0, maxLen - 1) + '\u2026' : prompt;
  1601‚Üí        title += ` \u2014 ${truncated}`;
  1602‚Üí      }
  1603‚Üí    }
  1604‚Üí
  1605‚Üí    title += ` [${shortId}]`;
  1606‚Üí    return title.length > 100 ? title.slice(0, 97) + '...' : title;
  1607‚Üí  }
