  1609‚Üí  /** Detect if tool activity targets a different project than session cwd */
  1610‚Üí  private detectEffectiveProject(sessionCwd: string, paths: string[]): string | null {
  1611‚Üí    if (paths.length < 3) return null;
  1612‚Üí    const cwdNorm = sessionCwd.endsWith('/') ? sessionCwd : sessionCwd + '/';
  1613‚Üí
  1614‚Üí    // Find paths outside session cwd
  1615‚Üí    const outsidePaths = paths.filter(p => p.startsWith('/') && !p.startsWith(cwdNorm));
  1616‚Üí    if (outsidePaths.length < 3 || outsidePaths.length / paths.length < 0.3) return null;
  1617‚Üí
  1618‚Üí    // Extract project name at the path divergence point
  1619‚Üí    const cwdParts = sessionCwd.split('/');
  1620‚Üí    const projects = new Map<string, number>();
  1621‚Üí
  1622‚Üí    for (const p of outsidePaths) {
  1623‚Üí      const parts = p.split('/');
  1624‚Üí      let divergeAt = 0;
  1625‚Üí      for (let i = 0; i < Math.min(parts.length, cwdParts.length); i++) {
  1626‚Üí        if (parts[i] !== cwdParts[i]) { divergeAt = i; break; }
  1627‚Üí        divergeAt = i + 1;
  1628‚Üí      }
  1629‚Üí      const name = parts[divergeAt];
  1630‚Üí      if (name) projects.set(name, (projects.get(name) || 0) + 1);
  1631‚Üí    }
  1632‚Üí
  1633‚Üí    let dominant: string | null = null;
  1634‚Üí    let maxCount = 0;
  1635‚Üí    for (const [name, count] of projects) {
  1636‚Üí      if (count > maxCount) { maxCount = count; dominant = name; }
  1637‚Üí    }
  1638‚Üí    return dominant;
  1639‚Üí  }
