  1641‚Üí  // ‚îÄ‚îÄ Rendering ‚îÄ‚îÄ
  1642‚Üí
  1643‚Üí  /**
  1644‚Üí   * Resolve a short name to a full cwd path.
  1645‚Üí   * Search chain: recent sessions ‚Üí zoxide query.
  1646‚Üí   */
  1647‚Üí  private resolveCwdShortcut(name: string): string | null {
  1648‚Üí    const lower = name.toLowerCase();
  1649‚Üí
  1650‚Üí    // 1. Recent/active sessions
  1651‚Üí    for (const session of this.registry.listAll()) {
  1652‚Üí      const project = session.project.toLowerCase();
  1653‚Üí      if (project === lower || project.includes(lower)) {
  1654‚Üí        return session.cwd;
  1655‚Üí      }
  1656‚Üí    }
  1657‚Üí
  1658‚Üí    // 2. zoxide query (frecency-based, same as `z` command)
  1659‚Üí    try {
  1660‚Üí      const result = execSync(`zoxide query ${name}`, {
  1661‚Üí        encoding: 'utf-8',
  1662‚Üí        timeout: 2000,
  1663‚Üí        stdio: ['pipe', 'pipe', 'pipe'],
  1664‚Üí      }).trim();
  1665‚Üí      if (result && result.startsWith('/')) return result;
  1666‚Üí    } catch {
  1667‚Üí      // zoxide not installed or no match
  1668‚Üí    }
  1669‚Üí
  1670‚Üí    return null;
  1671‚Üí  }
