  1673‚Üí  private parseInput(input: unknown): Record<string, unknown> {
  1674‚Üí    if (input !== null && typeof input === 'object') return input as Record<string, unknown>;
  1675‚Üí    if (typeof input === 'string') {
  1676‚Üí      try { return JSON.parse(input); } catch { return {}; }
  1677‚Üí    }
  1678‚Üí    return {};
  1679‚Üí  }
