  1681‚Üí  /** Extract readable text from Claude Code's various tool output formats */
  1682‚Üí  private extractOutputText(output: unknown): string {
  1683‚Üí    if (typeof output === 'string') return output;
  1684‚Üí    if (output === null || output === undefined) return '';
  1685‚Üí    if (Array.isArray(output)) {
  1686‚Üí      // [{type:"text", text:"..."}, ...] ‚Äî Claude API content blocks
  1687‚Üí      const texts = output
  1688‚Üí        .filter((b) => b && typeof b === 'object' && (b as Record<string, unknown>).type === 'text')
  1689‚Üí        .map((b) => String((b as Record<string, unknown>).text || ''));
  1690‚Üí      return texts.length > 0 ? texts.join('\n') : JSON.stringify(output, null, 2);
  1691‚Üí    }
  1692‚Üí    if (typeof output === 'object') {
  1693‚Üí      const o = output as Record<string, unknown>;
  1694‚Üí      // Bash: {stdout, stderr, interrupted, ...}
  1695‚Üí      if (typeof o.stdout === 'string') {
  1696‚Üí        let text = o.stdout;
  1697‚Üí        if (typeof o.stderr === 'string' && o.stderr) text += `\n[stderr] ${o.stderr}`;
  1698‚Üí        return text;
  1699‚Üí      }
  1700‚Üí      if (typeof o.content === 'string') return o.content;                      // {content:"text"}
  1701‚Üí      if (Array.isArray(o.content)) return this.extractOutputText(o.content);   // {type:"tool_result",content:[...]}
  1702‚Üí      if (typeof o.output === 'string') return o.output;                        // {output:"text"}
  1703‚Üí      if (typeof o.text === 'string') return o.text;                            // {text:"..."}
  1704‚Üí      if (typeof o.result === 'string') return o.result;                        // {result:"text"}
  1705‚Üí      // Edit/Write: {filePath, success}
  1706‚Üí      if (typeof o.filePath === 'string' && typeof o.success === 'boolean') {
  1707‚Üí        return o.success ? `\u2713 ${o.filePath}` : `\u2717 ${o.filePath}`;
  1708‚Üí      }
  1709‚Üí      return JSON.stringify(output, null, 2);
  1710‚Üí    }
  1711‚Üí    return String(output);
  1712‚Üí  }
