  1714‚Üí  private renderEvent(eventType: string, data: unknown, agent?: string): RenderedMessage {
  1715‚Üí    const brand = getAgentBrand(agent || 'unknown');
  1716‚Üí    const author = { name: brand.label, ...(brand.iconUrl ? { icon_url: brand.iconUrl } : {}) };
  1717‚Üí    switch (eventType) {
  1718‚Üí      case 'text':
  1719‚Üí        return { text: String(data) };
  1720‚Üí
  1721‚Üí      case 'user_prompt': {
  1722‚Üí        const d = data as { prompt?: string };
  1723‚Üí        const prompt = d.prompt || String(data);
  1724‚Üí        const truncated = prompt.length > 500 ? prompt.slice(0, 500) + '...' : prompt;
  1725‚Üí        return { text: `**User:** ${truncated}` };
  1726‚Üí      }
  1727‚Üí
  1728‚Üí      case 'tool_use': {
  1729‚Üí        const d = data as { name?: string; input?: unknown };
  1730‚Üí        const inp = this.parseInput(d.input);
  1731‚Üí        let summary = '';
  1732‚Üí        if (inp.command) summary = `\`${String(inp.command).slice(0, 100)}\``;
  1733‚Üí        else if (inp.file_path) summary = `\`${String(inp.file_path)}\``;
  1734‚Üí        else if (inp.pattern) summary = `\`${String(inp.pattern)}\``;
  1735‚Üí        return { text: `**${d.name || 'unknown'}** ${summary}`.trim() };
  1736‚Üí      }
  1737‚Üí
  1738‚Üí      case 'tool_result': {
  1739‚Üí        const d = data as { tool?: string; input?: unknown; output?: unknown; content?: string; is_error?: boolean };
  1740‚Üí        const tool = d.tool || 'unknown';
  1741‚Üí        const isError = d.is_error === true;
  1742‚Üí
  1743‚Üí        // Parse input (may be JSON string from hook's jq -c)
  1744‚Üí        const inp = this.parseInput(d.input);
  1745‚Üí        let inputSummary = '';
  1746‚Üí        if (inp.command) inputSummary = String(inp.command).slice(0, 100);
  1747‚Üí        else if (inp.file_path) inputSummary = String(inp.file_path);
  1748‚Üí        else if (inp.pattern) inputSummary = String(inp.pattern);
  1749‚Üí        else if (inp.query) inputSummary = String(inp.query).slice(0, 100);
  1750‚Üí
  1751‚Üí        // Extract readable text from output (handles string, content-block arrays, and wrapped objects)
  1752‚Üí        let output = this.extractOutputText(d.output);
  1753‚Üí        if (!output && d.content) output = d.content;
  1754‚Üí
  1755‚Üí        // Build embed with description (renders with visible colored side bar)
  1756‚Üí        const titleLine = `${isError ? '\u274c' : '\ud83d\udd27'} ${tool}${inputSummary ? ` \u2014 ${inputSummary}` : ''}`;
  1757‚Üí        let description: string | undefined;
  1758‚Üí        if (output) {
  1759‚Üí          const truncated = output.length > 800
  1760‚Üí            ? output.slice(0, 800) + `\n[truncated, ${output.length} chars total]`
  1761‚Üí            : output;
  1762‚Üí          description = `\`\`\`\n${truncated}\n\`\`\``;
  1763‚Üí        }
  1764‚Üí
  1765‚Üí        return {
  1766‚Üí          embed: {
  1767‚Üí            author,
  1768‚Üí            title: titleLine.length > 256 ? titleLine.slice(0, 253) + '...' : titleLine,
  1769‚Üí            description,
  1770‚Üí            color: isError ? 0xED4245 : 0x57F287,
  1771‚Üí            timestamp: new Date().toISOString(),
  1772‚Üí          },
  1773‚Üí        };
  1774‚Üí      }
  1775‚Üí
  1776‚Üí      case 'error':
  1777‚Üí        return {
  1778‚Üí          embed: {
  1779‚Üí            author,
  1780‚Üí            title: '\ud83d\udea8 Error',
  1781‚Üí            description: String(data),
  1782‚Üí            color: 0xED4245,
  1783‚Üí          },
  1784‚Üí        };
  1785‚Üí
  1786‚Üí      case 'result': {
  1787‚Üí        const d = data as { usage?: { cost_usd?: number; input_tokens?: number; output_tokens?: number } };
  1788‚Üí        const usage = d.usage;
  1789‚Üí        return {
  1790‚Üí          embed: {
  1791‚Üí            author,
  1792‚Üí            title: '\u2705 Done',
  1793‚Üí            color: 0x57F287,
  1794‚Üí            ...(usage ? {
  1795‚Üí              footer: {
  1796‚Üí                text: `Cost: $${(usage.cost_usd || 0).toFixed(4)} | In: ${usage.input_tokens} | Out: ${usage.output_tokens}`,
  1797‚Üí              },
  1798‚Üí            } : {}),
  1799‚Üí          },
  1800‚Üí        };
  1801‚Üí      }
  1802‚Üí
  1803‚Üí      case 'notification': {
  1804‚Üí        if (typeof data === 'string') return { text: data };
  1805‚Üí        const nd = data as Record<string, unknown>;
  1806‚Üí        const raw = nd.message ?? nd.title ?? nd.summary;
  1807‚Üí        // Ensure we always produce a string ‚Äî nd.message may be an object in some Claude Code versions
  1808‚Üí        const summary = typeof raw === 'string'
  1809‚Üí          ? raw
  1810‚Üí          : (raw != null ? JSON.stringify(raw, null, 2) : JSON.stringify(data, null, 2));
  1811‚Üí        if (!summary) return { text: '' };
  1812‚Üí        const truncated = summary.length > 500 ? summary.slice(0, 500) + '...' : summary;
  1813‚Üí        return { text: truncated };
  1814‚Üí      }
  1815‚Üí
  1816‚Üí      default:
  1817‚Üí        return { text: `[${eventType}] ${typeof data === 'string' ? data : JSON.stringify(data, null, 2)}` };
  1818‚Üí    }
  1819‚Üí  }
  1820‚Üí}
